#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int *indeg = (int*)calloc(N+1, sizeof(int));
        for(int i=0;i<N-1;i++){
            int u,v; scanf("%d %d", &u, &v);
            indeg[v]++;
        }
        int zeros=0;
        for(int i=1;i<=N;i++) if(indeg[i]==0) zeros++;
        printf("%d\n", zeros-1);
        free(indeg);
    }
    return 0;
}

